def dump(path,obj):
 p=ROOT/path;p.parent.mkdir(parents=True,exist_ok=True);p.write_text(json.dumps(obj,ensure_ascii=False,indent=2)+'\n',encoding='utf-8')

def svg_card(path,title,subtitle,chapter,index,kind):
 p=ROOT/path;p.parent.mkdir(parents=True,exist_ok=True)
 title=html.escape(title);subtitle=html.escape(subtitle);marks=['♜','▥','✎','◇','⚭','⌂','⚓','◆','◉','◷'];acc=['#c99f58','#6f9ec2','#8ca6b5','#d4b06a','#b98678','#9d8662','#4f9aa3','#bc7d50','#5b9eaa','#a36f5d'][chapter-1]
 p.write_text(f'''<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 720 900" role="img" aria-label="{title}"><defs><linearGradient id="g" x2="1" y2="1"><stop stop-color="#080b0d"/><stop offset=".55" stop-color="#20272b"/><stop offset="1" stop-color="#090708"/></linearGradient><radialGradient id="r"><stop stop-color="{acc}" stop-opacity=".46"/><stop offset="1" stop-color="{acc}" stop-opacity="0"/></radialGradient></defs><rect width="720" height="900" fill="url(#g)"/><circle cx="560" cy="170" r="270" fill="url(#r)"/><path d="M0 680 C150 605 270 725 430 650 S620 620 720 650 V900 H0Z" fill="#050607" opacity=".93"/><path d="M62 112 H658 M62 790 H658" stroke="{acc}" stroke-width="2" opacity=".85"/><text x="62" y="82" fill="{acc}" font-size="20" font-family="Arial" letter-spacing="4">INTERNATIONAL BRONZE AGE · {chapter:02d}</text><text x="560" y="360" text-anchor="middle" fill="{acc}" font-size="165" font-family="serif" opacity=".88">{marks[chapter-1]}</text><path d="M90 455 C220 400 330 505 445 450 S605 425 660 462" fill="none" stroke="{acc}" stroke-width="7" opacity=".32"/><text x="62" y="654" fill="#fff8e9" font-size="42" font-family="Georgia">{title[:30]}</text><text x="62" y="710" fill="#d8d0c2" font-size="23" font-family="Arial">{subtitle[:52]}</text><text x="62" y="832" fill="{acc}" font-size="18" font-family="Arial" letter-spacing="3">{kind.upper()} · CODEX OF HISTORY · {index:02d}</text></svg>''',encoding='utf-8')

